@pytest.mark.asyncio
async def test_scrape_asset_dedup() -> None:
    """Same asset linked twice results in one download with one unique hash."""
    engine_config = CrawlConfig(download_assets=True)
    engine = create_engine(engine_config)
    url = (
        os.environ.get("MOCK_SERVER_SCRAPE_ASSET_DEDUP")
        or os.environ["MOCK_SERVER_URL"] + "/fixtures/scrape_asset_dedup"
    )

    result = await scrape(engine, url)
    assert result.status_code == 200  # noqa: S101
    assert len(result.assets) == 2  # noqa: S101
    assert result.assets[0].content_hash  # noqa: S101


